package controller;
import dto.User;import java.io.IOException;import java.math.BigDecimal;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import mylib.AppKeys;import service.LoyaltyService;
@WebServlet(name="ApplyVoucherServlet",urlPatterns={"/booking/apply-voucher"})
public class ApplyVoucherServlet extends HttpServlet{protected void doPost(HttpServletRequest q,HttpServletResponse p)throws IOException{HttpSession s=q.getSession(false);User u=s==null?null:(User)s.getAttribute(AppKeys.SESSION_ACCOUNT);if(u==null){p.sendError(401);return;}try{int bookingId=Integer.parseInt(q.getParameter("bookingId"));BigDecimal total=new LoyaltyService().applyVoucher(u.getId(),bookingId,q.getParameter("voucherCode"));s.setAttribute("flashSuccess","Áp dụng voucher thành công. Thành tiền: "+total);}catch(IllegalArgumentException e){s.setAttribute("flashError",e.getMessage());}catch(Exception e){log("Apply voucher failed",e);s.setAttribute("flashError","Không thể hoàn tất thao tác. Vui lòng thử lại.");}p.sendRedirect(q.getContextPath()+"/booking-history");}}
